--- a/shifter.sv
+++ b/shifter.sv
@@ -1,14 +1,14 @@
 module BarrelShifter8bit (
   input [7:0] data_in,
   input [2:0] shift_amount,
   input shift_left,
   output [7:0] data_out
 );
   always @(*) begin
     if (shift_left)
       data_out = data_in << shift_amount;
     else
       data_out = data_in >> shift_amount;
   end
 endmodule

 module testbench;
-  wire [7:0] result;
-  BarrelShifter8bit shifter (.data_in(8'hAA), .shift_amount(3'b010), .data_out(result));
+  wire [7:0] result;
+  BarrelShifter8bit shifter (.data_in(8'hAA), .shift_amount(3'b010), .shift_left(1'b1), .data_out(result));
 endmodule

